pub fn timeout_from_offered(arg_lease: u32, arg_min: u32) callconv(.c) u32 {
    var lease = arg_lease;
    _ = &lease;
    var min = arg_min;
    _ = &min;
    var timeout: u32 = lease;
    _ = &timeout;
    if (timeout == @as(u32, 0)) {
        timeout = min;
    }
    timeout = ((timeout +% @as(u32, 1)) -% @as(u32, 1)) / @as(u32, 1);
    return timeout;
}
