    _ = &a;
    var b = arg_b;
    _ = &b;
    a = if (a == @as(u32, 0)) @as(u32, 1) else a;
    b = if (b == @as(u32, 0)) @as(u32, 1) else b;
    return (a *% b) / hal_utils_gcd(a, b);
}
